SELECT COUNT(DISTINCT S.PK_SIAPE) FROM SERVIDOR S JOIN CALC_HORA_AULA_MEDIA CH ON CH.SIAPE = S.PK_SIAPE WHERE LOWER(COALESCE(S.CONTRATO,'')) = 'efetivos' AND LOWER(COALESCE(S.AREA_INGRESSO,'')) LIKE '%biologia geral%' AND LOWER(COALESCE(S.SIGLA_CAMPUS,'')) = 'luz' AND CH.ANO = 2023 AND CH.SEMESTRE = 2 AND LOWER(COALESCE(CH.SIGLA_CAMPUS,'')) = 'luz'